import { visit } from "unist-util-visit";

/**
 * Prefix root-relative links in Markdown with the site's base path.
 *
 * The pages under `content/docs/linhas/` are generated by the pipeline and committed, so
 * they cannot carry the base path: it is a deployment concern, configurable per fork
 * (`BASE_PATH`), and baking it into the content would tie the dataset to one hosting.
 * Starlight rewrites the links it owns — the sidebar, the pagination — but not the ones
 * inside the Markdown body, which is where every station link lives.
 *
 * Absolute URLs, anchors, `mailto:` and links already carrying the base are left alone.
 */
const ATTRIBUTE = { a: "href", img: "src", source: "src" };

export function rehypeBasePath(base) {
  const prefix = base.endsWith("/") ? base.slice(0, -1) : base;

  return () => (tree) => {
    if (!prefix) return;
    visit(tree, "element", (node) => {
      const attribute = ATTRIBUTE[node.tagName];
      const value = attribute && node.properties?.[attribute];
      if (typeof value !== "string") return;
      if (!value.startsWith("/") || value.startsWith("//")) return;
      if (value === prefix || value.startsWith(`${prefix}/`)) return;
      node.properties[attribute] = `${prefix}${value}`;
    });
  };
}
